import xml.etree.ElementTree as ET
from xml.etree.ElementTree import ParseError
import sys
from schematics3 import AutoSchema, ValidationError
from schematics3.exceptions import RequiredMissing
from lxml import etree
from xml.schema import XMLValidationReport

def read_validate_xml(file):
    try:
        tree = ET.parse(file)
        root = tree.getroot()
    except FileNotFoundError:
        print("File not found")
        sys.exit(1)
    except ParseError as e:
        print("Error while parsing XML:", e.msg)
        sys.exit(1)

    schema = AutoSchema(strict=True)
    try:
        validated_data = schema.validate(etree.tostring(root, encoding="unicode", method="xml"))
    except (ValidationError, RequiredMissing):
        print("XML validation failed")
        sys.exit(1)

    return root